body.script:
/* ── Helpers ── */
function hms(s) {
  s = Math.max(0, Math.round(s));
  const h = String(Math.floor(s/3600)).padStart(2,'0');
  const m = String(Math.floor((s%3600)/60)).padStart(2,'0');
  const sc= String(s%60).padStart(2,'0');
  return `${h}:${m}:${sc}`;
}
function fmtBytes(n) {
  n = Number(n)||0;
  if (n < 1024) return n+' B';
  const u=['KB','MB','GB','TB']; let i=-1;
  do { n/=1024; i++; } while(n>=1024&&i<u.length-1);
  return n.toFixed(1)+' '+u[i];
}
function fmtAgo(ts){
  const s=Math.floor(Date.now()/1000)-ts;
  if(s<60) return s+'s ago';
  if(s<3600) return Math.floor(s/60)+'m ago';
  return Math.floor(s/3600)+'h ago';
}
function toast(msg){ /* lightweight toast via status bar flash — not implemented in skeleton */ }

/* ── State ── */
let session = null;          // null = not connected
let sessionDuration = null;
let plans = [];
let sheetOpen = false;
let paymentOptions = [];
let wizState = { open:false, step:'plan', plan:null, payOption:null, paymentId:null, payType:null, payData:null, pollTimer:null };
let pollTimer = null;

/* ── Load portal config ── */
fetch('/api/portal/config').then(r=>r.json()).then(d=>{
  if(d.ok){
    const displayName = d.branding?.portal_name || d.app?.name || 'PAYWIFI';
    const tagline     = d.app?.tagline || '';
    document.getElementById('app-name').textContent    = displayName;
    document.getElementById('app-subtitle').textContent= tagline;
    document.title = displayName;
    // Wire in footer powered-by
    const sbFooter = document.querySelector('.status-footer');
    if(sbFooter) sbFooter.textContent = 'Powered by ' + displayName;
  }
}).catch(()=>{});

/* ── Load plans ── */
function renderPlanCard(plan, targetId) {
  const isActive = session && session.plan_name === plan.name;
  const isConnected = !!session;
  return `



      ${plan.speed}

₱${plan.price}

${plan.duration_label}

    ${isActive
      ? 'Active'
      : isConnected ? 'In Use'
      : 'Buy Voucher'}
  `;
}

function renderPlans() {
  const dg = document.getElementById('plans-grid-desktop');
  const mg = document.getElementById('plans-grid-mobile');
  const wg = document.getElementById('wiz-plans-grid');
  const html = plans.length
    ? plans.map(p=>renderPlanCard(p)).join('')
    : '
No plans available.';
  dg.innerHTML = html;
  mg.innerHTML = html;

  // Wizard plan grid
  if(wg) wg.innerHTML = plans.map(p=>`



        ${p.speed}

₱${p.price}

${p.duration_label}

      Select 
    `).join('');
}

fetch('/api/portal/plans').then(r=>r.json()).then(d=>{
  if(d.ok){ plans=d.plans; renderPlans(); }
}).catch(()=>{});

/* ── Session polling ── */
function applySession(data) {
  if (!data.authenticated) {
    setDisconnected();
    return;
  }
  session = data;
  if (!sessionDuration && data.started_at && data.expires_at)
    sessionDuration = data.expires_at - data.started_at;

  const rem = data.remaining_seconds || 0;
  const pct = sessionDuration ? Math.min(100,(rem/sessionDuration)*100) : 100;

  // Header timer
  const ht = document.getElementById('header-timer');
  ht.textContent = hms(rem);
  ht.classList.remove('dim');

  // Session view
  document.getElementById('form-view').classList.add('hidden');
  document.getElementById('session-view').classList.remove('hidden');

  const timerEl = document.getElementById('session-timer');
  timerEl.textContent = hms(rem);
  timerEl.className = 'val' + (rem<300?' crit':rem<600?' warn':'');

  document.getElementById('bytes-in').textContent  = fmtBytes(data.bytes_in);
  document.getElementById('bytes-out').textContent = fmtBytes(data.bytes_out);
  document.getElementById('pct-label').textContent = Math.round(pct)+'% remaining';

  const fill = document.getElementById('prog-fill');
  fill.style.width = pct+'%';
  fill.className = 'prog-fill'+(pct<10?' crit':pct<20?' warn':'');

  // Status bar
  const dot  = document.getElementById('sb-dot');
  const text = document.getElementById('sb-text');
  dot.className  = 'status-dot connected';
  text.className = 'status-text connected';
  text.textContent = 'Connected' + (data.plan_name ? ' · '+data.plan_name : '');

  // Device info in status bar
  if(data.ip) {
    document.getElementById('sb-ip').textContent = data.ip;
    document.getElementById('sb-ip').classList.remove('hidden');
    document.getElementById('sb-sep').classList.remove('hidden');
  }

  renderPlans();
}

function setDisconnected() {
  session = null; sessionDuration = null;
  document.getElementById('form-view').classList.remove('hidden');
  document.getElementById('session-view').classList.add('hidden');

  const ht = document.getElementById('header-timer');
  ht.textContent = '00:00:00';
  ht.classList.add('dim');

  document.getElementById('sb-dot').className  = 'status-dot disconnected';
  document.getElementById('sb-text').className = 'status-text disconnected';
  document.getElementById('sb-text').textContent = 'Not Connected';
  document.getElementById('sb-ip').classList.add('hidden');
  document.getElementById('sb-sep').classList.add('hidden');
  renderPlans();
}

async function pollSession() {
  try {
    const r = await fetch('/api/session/status');
    const d = await r.json();
    if(d.ok) applySession(d);
  } catch(e) {}
}

pollSession();
setInterval(pollSession, 10000);

/* ── Connect ── */
document.getElementById('btn-connect').addEventListener('click', submitVoucher);
document.getElementById('voucher-input').addEventListener('keydown', e=>{ if(e.key==='Enter') submitVoucher(); });

async function submitVoucher(force=false) {
  const code = document.getElementById('voucher-input').value.trim().toUpperCase();
  if(!code){ return; }
  const btn = document.getElementById('btn-connect');
  const lbl = document.getElementById('connect-label');
  btn.disabled = true;
  lbl.textContent = 'Connecting…';

  try {
    const r = await fetch('/api/auth/voucher', {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({code, force: force===true})
    });
    const d = await r.json().catch(()=>({}));

    if(d.ok){ pollSession(); document.getElementById('voucher-input').value=''; return; }

    if(r.status===409 && d.code==='DEVICE_LIMIT'){
      showDeviceModal(d.sessions||[], code);
      return;
    }

    // Show error briefly in connect label
    lbl.textContent = d.error || 'Invalid code';
    setTimeout(()=>{ lbl.textContent='Connect'; btn.disabled=false; }, 2500);
    return;
  } catch(e) {
    lbl.textContent = 'Network error';
    setTimeout(()=>{ lbl.textContent='Connect'; btn.disabled=false; }, 2500);
    return;
  }
  btn.disabled = false;
  lbl.textContent = 'Connect';
}

/* ── Disconnect ── */
document.getElementById('btn-disconnect').addEventListener('click', async ()=>{
  if(!confirm('Disconnect from the network?')) return;
  try { await fetch('/api/session/logout',{method:'POST'}); } catch(e){}
  setDisconnected();
});

/* ── Mobile sheet ── */
document.getElementById('sheet-toggle').addEventListener('click',()=>{
  sheetOpen = !sheetOpen;
  document.getElementById('sheet').classList.toggle('open', sheetOpen);
  const ch = document.getElementById('sheet-chevron');
  ch.style.transform = sheetOpen ? 'rotate(180deg)' : '';
});

/* ── Buy Wizard ── */
function openWizard(planId) {
  if(wizState.pollTimer){ clearInterval(wizState.pollTimer); }
  wizState = { open:true, step:'plan', plan:null, payOption:null, paymentId:null, payType:null, payData:null, pollTimer:null };
  const p = plans.find(x=>x.id===planId);
  if(p) { wizState.step='checkout'; wizState.plan=p; }
  renderWizard();
  document.getElementById('wizard-overlay').classList.add('open');
}
function closeWizard() {
  if(wizState.pollTimer){ clearInterval(wizState.pollTimer); }
  document.getElementById('wizard-overlay').classList.remove('open');
  wizState = { open:false, step:'plan', plan:null, payOption:null, paymentId:null, payType:null, payData:null, pollTimer:null };
}
document.getElementById('btn-wiz-close').addEventListener('click', closeWizard);
document.getElementById('wizard-overlay').addEventListener('click', e=>{
  if(e.target===e.currentTarget) closeWizard();
});

function wizSelectPlan(planId) {
  const p = plans.find(x=>x.id===planId);
  if(!p) return;
  wizState.plan = p;
  wizState.step = 'checkout';
  renderWizard();
}

function renderWizard() {
  const step = wizState.step;
  const plan = wizState.plan;
  const STEPS = { plan:1, checkout:2, pay:3, success:4 };
  const stepNum = STEPS[step] || 1;
  const total   = 4;
  const TITLES  = { plan:'Select Plan', checkout:'Payment', pay:'Complete Payment', success:'Confirmed' };

  document.getElementById('wiz-step-label').textContent = `Step ${stepNum} of ${total}`;
  document.getElementById('wiz-step-title').textContent = TITLES[step] || 'Select a Plan';

  // Dots
  const dotsEl = document.getElementById('wiz-dots');
  dotsEl.innerHTML = Array.from({length:total},(_,i)=>{
    const n=i+1;
    const cls = n===stepNum?'active':n<stepNum?'done':'next';
    return `
`;
  }).join('');

  // Show/hide steps
  document.getElementById('wiz-step-plan').classList.toggle('hidden', step!=='plan');
  document.getElementById('wiz-step-checkout').classList.toggle('hidden', step!=='checkout');
  document.getElementById('wiz-step-pay').classList.toggle('hidden', step!=='pay');
  document.getElementById('wiz-step-success').classList.toggle('hidden', step!=='success');

  // Render payment options grid when on checkout
  if (step==='checkout') renderWizPayOptions();

  // Context banner — success step only (✓ Paid confirmation)
  const ctx = document.getElementById('wiz-ctx');
  if (step==='success' && plan) {
    ctx.classList.remove('hidden');
    ctx.className = 'ctx-banner paid';
    document.getElementById('ctx-lbl').textContent    = '✓ Paid';
    document.getElementById('ctx-amount').textContent = `₱${plan.price}`;
    document.getElementById('ctx-method-name').textContent = wizState.payOption ? wizState.payOption.name : '—';
  } else { ctx.classList.add('hidden'); }

  // Payment method badge in header — only on pay step
  const badge    = document.getElementById('wiz-method-badge');
  const badgeName= document.getElementById('wiz-method-badge-name');
  if (step==='pay' && wizState.payOption) {
    badge.classList.remove('hidden');
    badgeName.textContent = wizState.payOption.name;
  } else { badge.classList.add('hidden'); }

  // Order summary (checkout step)
  if (step==='checkout' && plan) {
    document.getElementById('wiz-plan-name').textContent = plan.name;
    document.getElementById('wiz-plan-sub').textContent  = `${plan.speed} · ${plan.duration_label}`;
    document.getElementById('wiz-plan-price').textContent= `₱${plan.price}`;
  }
  // Plan banner (pay step)
  if (step==='pay' && plan) {
    document.getElementById('wiz-pay-plan-name').textContent  = plan.name;
    document.getElementById('wiz-pay-plan-sub').textContent   = `${plan.speed} · ${plan.duration_label}`;
    document.getElementById('wiz-pay-plan-price').textContent = `₱${plan.price}`;
  }

  // Footer
  const footer = document.getElementById('wiz-footer');
  if (step==='success') {
    footer.innerHTML=`


        Share


        Use Voucher

      `;
  } else if (step==='plan') {
    footer.innerHTML=`Cancel`;
  } else if (step==='checkout') {
    const hasOpt = !!wizState.payOption;
    footer.innerHTML=`


        Back


        ${hasOpt ? `Pay ₱${plan?plan.price:''} →` : 'Select a method'}
      `;
  } else if (step==='pay') {
    const isLoading = !wizState.payType;
    const isManual  = wizState.payType === 'manual';
    const isError   = wizState.payType === 'error';
    if (isLoading || isError) {
      footer.innerHTML=`← Back`;
    } else {
      footer.innerHTML=`


          Back


          ${isManual ? "I Have My Code" : "I've Already Paid"}
        `;
    }
  }
}

/* ── Wizard payment option rendering ── */
function renderWizPayOptions() {
  const grid = document.getElementById('wiz-pm-grid');
  if (!grid) return;
  if (!paymentOptions.length) {
    grid.innerHTML = '
No payment options configured.';
    return;
  }
  grid.innerHTML = paymentOptions.map(opt => {
    const sel = wizState.payOption && wizState.payOption.id === opt.id;
    const badge = opt.badge || '';
    const badgeCls = badge.toLowerCase()==='available' ? 'pm-badge pm-badge-available' :
                     badge.toLowerCase()==='new'       ? 'pm-badge pm-badge-new' : 'pm-badge';
    const icon = opt.icon_url
      ? ``
      : (PM_ICONS[opt.icon_key] || PM_ICONS.card);
    return `

${icon}
      ${opt.name}
      ${badge ? `${badge}` : ''}
    `;
  }).join('');
}

function selectWizPayOption(optId) {
  wizState.payOption = paymentOptions.find(o => o.id === optId) || null;
  renderWizPayOptions();
  // Re-render footer to enable/update the Continue button
  const plan = wizState.plan;
  const footer = document.getElementById('wiz-footer');
  footer.innerHTML=`


      Back


      Pay ₱${plan ? plan.price : '—'} →
    `;
}

function wizGoBack() {
  if (wizState.pollTimer) { clearInterval(wizState.pollTimer); wizState.pollTimer = null; }
  if (wizState.step === 'pay') {
    wizState.step = 'checkout'; wizState.payType = null; wizState.paymentId = null; wizState.payData = null;
  } else if (wizState.step === 'checkout') {
    wizState.step = 'plan'; wizState.payOption = null;
  }
  renderWizard();
}

async function continueToPayment() {
  if (!wizState.payOption || !wizState.plan) return;
  wizState.step    = 'pay';
  wizState.payType = null;   // triggers loading state
  renderWizard();

  try {
    const r = await fetch('/api/portal/payment/create', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ plan_id: wizState.plan.id, option_id: wizState.payOption.id })
    });
    const d = await r.json().catch(() => ({}));
    if (!d.ok) { showWizPayError(d.error || 'Could not start payment.', d.code === 'CHANNEL_NOT_ACTIVATED' ? 'Please go back and select a different payment method.' : ''); return; }
    wizState.paymentId = d.payment_id;
    wizState.payType   = d.type;
    wizState.payData   = d;
    showPayStep(d);
    if (d.type !== 'manual') {
      wizState.pollTimer = setInterval(pollPaymentStatus, 3000);
    }
  } catch (e) {
    showWizPayError('Network error. Please try again.');
  }
}

function showPayStep(data) {
  ['loading','qr','ewallet','manual','error'].forEach(k => {
    const el = document.getElementById('wiz-pay-'+k);
    if (el) el.classList.add('hidden');
  });
  const type = data.type;
  if (type === 'qr_code') {
    const el = document.getElementById('wiz-pay-qr');
    el.classList.remove('hidden');
    if (data.qr_image) { document.getElementById('wiz-qr-img').src = data.qr_image; }
    const chNameEl = document.getElementById('wiz-qr-channel-name');
    if (chNameEl) chNameEl.textContent = wizState.payOption ? wizState.payOption.name : 'QR Code';
  } else if (type === 'ewallet') {
    const el = document.getElementById('wiz-pay-ewallet');
    el.classList.remove('hidden');
    const name = wizState.payOption ? wizState.payOption.name : 'eWallet';
    document.getElementById('wiz-ewallet-name').textContent  = name;
    document.getElementById('wiz-ewallet-name2').textContent = name;
    const link = document.getElementById('wiz-ewallet-link');
    if (data.checkout_url) link.href = data.checkout_url;
  } else if (type === 'otc') {
    const el = document.getElementById('wiz-pay-manual');
    el.classList.remove('hidden');
    const txt = document.getElementById('wiz-manual-text');
    const code = data.payment_code || '—';
    txt.innerHTML = `Show this payment code at any 7-Eleven or Cebuana Lhuillier branch:

${code}
Pay ₱${data.amount} for the ${wizState.plan ? wizState.plan.name : 'plan'}. Once paid, tap I Have My Code below.`;
  } else if (type === 'va') {
    const el = document.getElementById('wiz-pay-manual');
    el.classList.remove('hidden');
    const txt = document.getElementById('wiz-manual-text');
    const acct = data.va_number || '—';
    txt.innerHTML = `Transfer ₱${data.amount} to this virtual account:

${acct}
Once the transfer is confirmed, tap I Have My Code below.`;
  } else {
    const el = document.getElementById('wiz-pay-manual');
    el.classList.remove('hidden');
    const txt = document.getElementById('wiz-manual-text');
    txt.innerHTML = `Go to the counter and pay ₱${data.amount || (wizState.plan ? wizState.plan.price : '—')} for the ${wizState.plan ? wizState.plan.name : 'plan'}.

Once you have the code, tap I Have My Code below.`;
  }
  renderWizard();
}

function showWizPayError(msg, hint) {
  ['loading','qr','ewallet','manual'].forEach(k => {
    const el = document.getElementById('wiz-pay-'+k);
    if (el) el.classList.add('hidden');
  });
  const el = document.getElementById('wiz-pay-error');
  if (el) el.classList.remove('hidden');
  const msgEl = document.getElementById('wiz-pay-error-msg');
  if (msgEl) msgEl.textContent = msg;
  const hintEl = document.getElementById('wiz-pay-error-hint');
  if (hintEl) hintEl.textContent = hint || '';
  wizState.payType = 'error';
  renderWizard();
}

async function pollPaymentStatus() {
  if (!wizState.paymentId) return;
  try {
    const r = await fetch(`/api/portal/payment/status/${wizState.paymentId}`);
    const d = await r.json().catch(() => ({}));
    if (!d.ok) return;
    if (d.status === 'paid') {
      clearInterval(wizState.pollTimer); wizState.pollTimer = null;
      wizState.step = 'success';
      const code = (d.voucher_code || '').replace(/(.{4})(?=.)/g,'$1 ').trim();
      document.getElementById('wiz-voucher-code').textContent = code || 'ERROR';
      document.getElementById('wiz-voucher-sub').textContent  =
        wizState.plan ? `${wizState.plan.name} · ${wizState.plan.speed} · ₱${wizState.plan.price}` : '';
      renderWizard();
    } else if (d.status === 'expired') {
      clearInterval(wizState.pollTimer); wizState.pollTimer = null;
      showWizPayError('Payment window expired. Please start over.');
    }
  } catch (e) {}
}

function wizManualDone() {
  clearInterval(wizState.pollTimer);
  closeWizard();
  document.getElementById('voucher-input').focus();
}

async function wizClaimPaid() {
  if (!wizState.paymentId) return;
  const txt = document.getElementById('wiz-pay-status-text') || document.getElementById('wiz-pay-status-text2');
  if (txt) txt.textContent = 'Checking…';
  try {
    const r = await fetch(`/api/portal/payment/status/${wizState.paymentId}`);
    const d = await r.json().catch(() => ({}));
    if (d.ok && d.status === 'paid') {
      clearInterval(wizState.pollTimer); wizState.pollTimer = null;
      wizState.step = 'success';
      const code = (d.voucher_code||'').replace(/(.{4})(?=.)/g,'$1 ').trim();
      document.getElementById('wiz-voucher-code').textContent = code || 'ERROR';
      document.getElementById('wiz-voucher-sub').textContent  =
        wizState.plan ? `${wizState.plan.name} · ${wizState.plan.speed} · ₱${wizState.plan.price}` : '';
      renderWizard();
    } else {
      if (txt) txt.textContent = 'Not confirmed yet. Please complete payment.';
    }
  } catch (e) {
    if (txt) txt.textContent = 'Check failed. Please wait.';
  }
}

function copyWizardCode(){
  const code = document.getElementById('wiz-voucher-code').textContent.replace(/\s/g,'');
  if(code && code !== 'ENTERCODE')
    navigator.clipboard?.writeText(code).catch(()=>{});
}

function useVoucher() {
  const code = document.getElementById('wiz-voucher-code').textContent.replace(/\s/g,'');
  closeWizard();
  if(code && code !== 'ENTERCODE'){
    document.getElementById('voucher-input').value = code;
    document.getElementById('voucher-input').focus();
  }
}

function shareVoucher() {
  const plan = wizState.plan;
  const code = document.getElementById('wiz-voucher-code').textContent.replace(/\s/g,'');
  if(!plan) return;
  const text = `📶 WiFi Voucher: ${code}\nPlan: ${plan.name} (${plan.speed}) — ₱${plan.price}\n\nEnter the code on the WiFi portal to connect.`;
  if(navigator.share){ navigator.share({title:'PAYWIFI Voucher', text}).catch(()=>{}); }
  else { navigator.clipboard?.writeText(text).catch(()=>{}); }
}

/* ── Device-limit modal ── */
function showDeviceModal(sessions, code) {
  const list = document.getElementById('device-list');
  list.innerHTML = sessions.map(s=>`



IP   ${s.ip}

MAC  ${s.mac}

Connected ${fmtAgo(s.started_at)}
    `).join('');
  document.getElementById('device-overlay').dataset.code = code;
  document.getElementById('device-overlay').classList.add('open');

  // Reset connect button
  const btn = document.getElementById('btn-connect');
  const lbl = document.getElementById('connect-label');
  btn.disabled = false; lbl.textContent = 'Connect';
}

document.getElementById('btn-dm-cancel').addEventListener('click',()=>{
  document.getElementById('device-overlay').classList.remove('open');
});

document.getElementById('btn-dm-kick').addEventListener('click', async ()=>{
  const code = document.getElementById('device-overlay').dataset.code;
  const btn  = document.getElementById('btn-dm-kick');
  btn.disabled=true; btn.textContent='Disconnecting…';
  try {
    const r = await fetch('/api/auth/voucher',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({code,force:true})});
    const d = await r.json().catch(()=>({}));
    document.getElementById('device-overlay').classList.remove('open');
    if(d.ok){ document.getElementById('voucher-input').value=''; pollSession(); }
    else {
      const lbl=document.getElementById('connect-label');
      lbl.textContent=d.error||'Error';
      setTimeout(()=>lbl.textContent='Connect',2500);
    }
  } catch(e){
    document.getElementById('device-overlay').classList.remove('open');
  }
  btn.disabled=false; btn.textContent='Disconnect & Continue';
});

/* ── Payment Options ── */
const PM_ICONS = {
  cash:     '',
  card:     '',
  qr:       '',
  mobile:   '',
  computer: '',
  bank:     '',
  wallet:   ''
};

function renderPaymentOptions(opts) {
  const grid = document.getElementById('pm-grid');
  if (!grid) return;
  if (!opts || !opts.length) { grid.innerHTML = ''; return; }
  grid.innerHTML = opts.map(o => {
    const key   = (o.icon_key || 'card').toLowerCase();
    const wrap  = 'pm-icon-wrap pm-icon-wrap-' + key;
    const icon  = o.icon_url
      ? ''
      : (PM_ICONS[key] || PM_ICONS.card);
    const badge = o.badge ? o.badge : '';
    const badgeCls = badge.toLowerCase() === 'available'
      ? 'pm-badge pm-badge-available'
      : badge.toLowerCase() === 'new'
      ? 'pm-badge pm-badge-new'
      : 'pm-badge';
    return '
'
      + '
' + icon + ''
      + '' + o.name + ''
      + (badge ? '' + badge + '' : '')
      + '';
  }).join('');
}

fetch('/api/portal/payment-options').then(r=>r.json()).then(d=>{
  if(d.ok){ paymentOptions = d.options; renderPaymentOptions(paymentOptions); }
}).catch(()=>{});
